j:jelly.script:
// IIFE scope-guard: `_rtimer`, `_scheduleRedraw`, `drawChart`, and
// `noData` are declared with `var`/`function` and would land in the
// browser's global scope. Four sibling widgets (patched, non_patched,
// priority_trend, team_trend) declare identically-named helpers, so
// whichever loads last would overwrite the others. Wrapping the body
// in an IIFE keeps every helper closure-scoped; the only intentional
// global is `window.__mttrTeamCasetypeState` (needed to tear down
// stale listeners across SN re-renders — see the block below).
(function () {
    google.charts.load('current', { packages: ['corechart'] });
    google.charts.setOnLoadCallback(function() { setTimeout(drawChart, 100); });

    var _rtimer = null;
    function _scheduleRedraw() {
        if (_rtimer) clearTimeout(_rtimer);
        _rtimer = setTimeout(drawChart, 150);
    }
    // Idempotent listener setup — see mttr_widget_hist_inc_priority.xml
    // for the rationale (SN re-renders re-run this script; naive
    // addEventListener leaks a handler on every mount).
    if (window.__mttrTeamCasetypeState) {
        window.removeEventListener('resize', window.__mttrTeamCasetypeState.resizeHandler);
        if (window.__mttrTeamCasetypeState.observer) {
            window.__mttrTeamCasetypeState.observer.disconnect();
        }
    }
    window.addEventListener('resize', _scheduleRedraw);
    var _obsTeamCasetype = null;
    if (typeof ResizeObserver !== 'undefined') {
        _obsTeamCasetype = new ResizeObserver(_scheduleRedraw);
        _obsTeamCasetype.observe(document.getElementById('chart_team_casetype'));
    }
    window.__mttrTeamCasetypeState = { resizeHandler: _scheduleRedraw, observer: _obsTeamCasetype };

    function drawChart() {
        try {
            var _el = document.getElementById('chart_team_casetype');
            var _w = _el.offsetWidth;
            if (_w > 0) {
                _el.style.height = Math.max(250, Math.round(_w * 0.55)) + 'px';
            }
            var raw = document.getElementById('mttr_data_team_casetype').value;
            if (!raw || raw === 'null' || raw === '[]') { noData(); return; }
            var teamData = JSON.parse(raw);
            if (!teamData || teamData.length === 0) { noData(); return; }

            var rows = [['Team', 'Incident', 'Query']];
            for (var i = 0; teamData.length > i; i++) {
                var t = teamData[i];
                rows.push([t.team, Math.round(((t.Incident || 0) / 24) * 10) / 10, Math.round(((t.Query || 0) / 24) * 10) / 10]);
            }

            var data = google.visualization.arrayToDataTable(rows);
            for (var f = 0; teamData.length > f; f++) {
                data.setFormattedValue(f, 1, teamData[f].Incident_display || '');
                data.setFormattedValue(f, 2, teamData[f].Query_display || '');
            }
            var chart = new google.visualization.ColumnChart(
                document.getElementById('chart_team_casetype'));
            chart.draw(data, {
                isStacked: false,
                chartArea: { width: '80%', height: '72%' },
                legend: { position: 'bottom', textStyle: { fontSize: 11 } },
                colors: ['#3498db', '#2ecc71'],
                backgroundColor: 'transparent',
                vAxis: {
                    title: 'Average Business Duration (Days)',
                    format: '#.#',
                    textStyle: { fontSize: 10 },
                    viewWindow: { min: 0 }
                },
                hAxis: { textStyle: { fontSize: 10 }, slantedText: true },
                tooltip: { textStyle: { fontSize: 11 } }
            });
        } catch (e) {
            console.error('mttr_widget_team_casetype error:', e);
            noData();
        }
    }

    function noData() {
        // DOM-API placeholder — see mttr_widget_team_trend.xml for
        // the full rationale (escaped-entity innerHTML rendered as
        // literal text; createElement produces a real p node).
        var container = document.getElementById('chart_team_casetype');
        container.innerHTML = '';
        var p = document.createElement('p');
        p.style.color = '#999';
        p.style.textAlign = 'center';
        p.style.padding = '40px';
        p.textContent = 'No data available';
        container.appendChild(p);
    }
})();
